const TRUSTED_DOMAINS = [
  'aljazeera.com', 'dawn.com', 'bbc.com', 'bbc.co.uk',
  'reuters.com', 'apnews.com', 'google.com', 'theguardian.com',
  'nytimes.com', 'npr.org', 'dw.com', 'france24.com'
];

const CLICKBAIT_KEYWORDS = [
  'you won\'t believe', 'shocking', 'mind blowing', 'goes viral',
  'breaks the internet', 'secret revealed', 'they don\'t want you to know',
  'number 5 will shock', 'this one trick', 'doctors hate',
  'click here', 'limited time', 'breaking!!!', 'omg'
];

const FAKE_INDICATORS = [
  'conspiracy', 'deep state', 'plandemic', 'hoax'
];

function isFromTrustedDomain(url) {
  if (!url) return false;
  try {
    // Clean URL before parsing
    const cleanUrl = url.split('?')[0].trim();
    const hostname = new URL(cleanUrl).hostname.replace('www.', '');
    return TRUSTED_DOMAINS.some(domain => hostname.includes(domain));
  } catch (e) {
    // If URL parse fails, check if the raw string contains a trusted domain
    return TRUSTED_DOMAINS.some(domain => (url || '').includes(domain));
  }
}

function hasClickbait(title) {
  if (!title) return false; // Don't reject if no title yet
  const lower = title.toLowerCase();
  return CLICKBAIT_KEYWORDS.some(kw => lower.includes(kw));
}

function hasFakeIndicators(text) {
  if (!text) return false;
  const lower = text.toLowerCase();
  return FAKE_INDICATORS.some(kw => lower.includes(kw));
}

function isRecent(pubDate) {
  if (!pubDate) return true; // Don't reject missing dates
  try {
    const articleDate = new Date(pubDate);
    if (isNaN(articleDate.getTime())) return true; // Don't reject unparseable dates
    const now = new Date();
    const hoursOld = (now - articleDate) / (1000 * 60 * 60);
    return hoursOld <= 48 && hoursOld >= -2; // Allow slight future dates (timezone issues)
  } catch (e) {
    return true;
  }
}

function hasMissingFields(item) {
  return !item.title || !item.link;  // Removed pubDate requirement
}

const items = $input.all();
const filtered = [];

for (const item of items) {
  const d = item.json;

  if (hasMissingFields(d)) continue;
  if (!isFromTrustedDomain(d.link)) continue;
  if (hasClickbait(d.title)) continue;
  if (hasFakeIndicators(d.title + ' ' + (d.contentSnippet || ''))) continue;
  if (!isRecent(d.pubDate)) continue;

  filtered.push({
    json: {
      title: d.title,
      link: d.link,
      pubDate: d.pubDate || new Date().toISOString(),
      snippet: d.contentSnippet || d['content:encodedSnippet'] || d.content || '',
      source: d.creator || d.source || (() => {
        try { return new URL(d.link).hostname.replace('www.',''); } 
        catch(e) { return 'Unknown'; }
      })(),
      publishedAt: (() => {
        try { return new Date(d.pubDate).toISOString(); }
        catch(e) { return new Date().toISOString(); }
      })()
    }
  });
}

// Remove duplicates by title similarity
const unique = [];
const seenTitles = [];
for (const item of filtered) {
  const cleanTitle = item.json.title.toLowerCase().replace(/[^a-z0-9 ]/g, '').slice(0, 40);
  if (!seenTitles.includes(cleanTitle)) {
    seenTitles.push(cleanTitle);
    unique.push(item);
  }
}

return unique.length > 0 ? unique : [{ json: { error: 'No articles passed filter', count: items.length } }];

const item = $input.first();

// AI output is in item.json
let summary = '';

if (typeof item.json.text === 'string') {
  summary = item.json.text;
} else if (item.json.message?.content) {
  summary = item.json.message.content;
} else if (item.json.output) {
  summary = item.json.output;
} else {
  summary = JSON.stringify(item.json);
}

// Get article data from the loop context
const loopData = $('Loop Articles').first().json;

return [{
  json: {
    title: loopData.title || '',
    source: loopData.source || '',
    link: loopData.link || '',
    pubDate: loopData.pubDate || '',
    summary: summary.trim()
  }
}];
